class Solution:
    def countExcellentPairs(self, nums, k):
        distinct = list(set(nums))
        cnt = 0
        for a in distinct:
            for b in distinct:
                if bin(a | b).count('1') + bin(a & b).count('1') >= k:
                    cnt += 1
        return cnt

