class Solution:
    def countExcellentPairs(self, nums, k):
        import bisect
        pcs = sorted(bin(v).count('1') for v in set(nums))
        cnt = 0
        for p in pcs:
            need = k - p
            idx = bisect.bisect_left(pcs, need)
            cnt += len(pcs) - idx
        return cnt

