var countExcellentPairs = function(nums, k) {
    const popcount = (x) => {
        let c = 0;
        while (x > 0) { c += x & 1; x = Math.floor(x / 2); }
        return c;
    };
    const pcs = [...new Set(nums)].map(popcount).sort((a, b) => a - b);
    const lowerBound = (arr, target) => {
        let lo = 0, hi = arr.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (arr[mid] < target) lo = mid + 1; else hi = mid;
        }
        return lo;
    };
    let cnt = 0;
    for (const p of pcs) {
        const idx = lowerBound(pcs, k - p);
        cnt += pcs.length - idx;
    }
    return cnt;
};
